// 组装推送内容，包含音频链接和公网练习链接
const aiOutput = $('AI英语老师').first().json;
const audioResult = $('生成音频文件').first().json;

// 从AI输出中提取各部分（如果AI遵循格式）
const raw = aiOutput.output || aiOutput.text || '';

function extractSection(markers, text) {
  for (const m of markers) {
    const regex = new RegExp(m + '[\s\S]*?([\s\S]*?)(?====|$)', 'i');
    const match = text.match(regex);
    if (match && match[1] && match[1].trim()) return match[1].trim();
  }
  return '';
}

const english = extractSection(['===ENGLISH==='], raw) || (aiOutput.output ? aiOutput.output.substring(0, 500) : '');
const translation = extractSection(['===TRANSLATION==='], raw);
const vocabulary = extractSection(['===VOCABULARY==='], raw);
const patterns = extractSection(['===PATTERNS==='], raw);
const grammar = extractSection(['===GRAMMAR==='], raw);
const quiz = extractSection(['===QUIZ==='], raw);
const encouragement = extractSection(['===ENCOURAGEMENT==='], raw);

const topicInfo = $('7日话题轮换').first().json;
const today = new Date();
const dateStr = today.toLocaleDateString('zh-CN', {
  year: 'numeric', month: 'long', day: 'numeric', weekday: 'long'
});

// 音频URL
const audioUrl = audioResult.data && audioResult.data.url ? audioResult.data.url : '';
const audioFilepath = audioResult.data && audioResult.data.filepath ? audioResult.data.filepath : '';

// 公网练习链接（GitHub Pages）
const followReadUrl = 'https://carriewin888.github.io/english-follow-read/follow_read.html';
const quizUrl = 'https://carriewin888.github.io/english-follow-read/quiz.html';
const chatUrl = 'https://carriewin888.github.io/english-follow-read/chat.html';

let markdown = '# ' + topicInfo.topic_emoji + ' 每日英语伴学
## ' + topicInfo.topic_name + ' | ' + dateStr + '

---

' +
  '## 🔊 跟读练习
👉 [点击这里开始跟读](' + followReadUrl + ')

' +
  '## ✍️ 答题练习
👉 [点击这里开始答题](' + quizUrl + ')

' +
  '## 💬 自由对话
👉 [点击这里和AI聊天](' + chatUrl + ')

' +
  '---

## 📝 英文原文
' + english + '

---

## 🌏 中文译文
' + (translation || '（待补充）') + '

---

## 📚 重点词汇
' + (vocabulary || '（待补充）') + '

---

## 🔑 重点句型
' + (patterns || '（待补充）') + '

---

## 📐 语法要点
' + (grammar || '（待补充）') + '

---

## ✅ 今日小测
' + (quiz || '（待补充）') + '

---

## 💪 今日鼓励
' + (encouragement || 'Keep going! 加油！') + '

---

## 🎧 音频朗读
' + (audioUrl ? '点击收听：' + audioUrl : '音频文件：' + audioFilepath) + '

---
*由AI英语伴学Agent自动生成 | 宁波初二专属*';

return [{
  json: {
    title: topicInfo.topic_emoji + ' 每日英语 | ' + topicInfo.topic_name,
    content: markdown,
    topic: topicInfo.topic_name,
    date: dateStr,
    english_text: english,
    audio_url: audioUrl,
    audio_path: audioFilepath
  }
}];

// 从AI输出中提取英文原文
const raw = $input.first().json.output || $input.first().json.text || '';

// 提取 ===ENGLISH=== 部分
let englishText = '';
const match = raw.match(/===ENGLISH===([\s\S]*?)(?====|$)/i);
if (match && match[1]) {
  englishText = match[1].trim();
}

// 如果没找到标记，取前800字符
if (!englishText || englishText.length < 50) {
  const lines = raw.split('\n');
  englishText = lines.slice(0, 8).join(' ').substring(0, 800);
}

const topicInfo = $('7日话题轮换').first().json;

return [{
  json: {
    english_text: englishText,
    speed: 1.0,
    voice: 'us_female',
    topic_name: topicInfo.topic_name || 'daily'
  }
}];
